import React, { useEffect, useState } from 'react';
import api from '../api';

const DoctorList = () => {
  const [doctors, setDoctors] = useState<any[]>([]);
  const [fName, setFName] = useState('');
  const [lName, setLName] = useState('');
  const [spec, setSpec] = useState('');
  const [email, setEmail] = useState('');

  const fetchDoctors = () => {
    api.get('doctors/').then((res: any) => setDoctors(res.data));
  };

  useEffect(() => { fetchDoctors(); }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      // Gi-match sa Django models.py fields
      await api.post('doctors/', { 
        first_name: fName, 
        last_name: lName, 
        specialization: spec,
        email: email 
      });
      setFName(''); setLName(''); setSpec(''); setEmail('');
      fetchDoctors();
      alert("Doctor Added!");
    } catch (err: any) {
      console.error("Doctor Error:", err.response?.data);
    }
  };

  const handleDelete = async (id: number) => {
    if (window.confirm("Delete this doctor?")) {
      await api.delete(`doctors/${id}/`);
      fetchDoctors();
    }
  };

  return (
    <div className="space-y-4">
      <form onSubmit={handleAdd} className="grid grid-cols-2 md:grid-cols-5 gap-2 bg-blue-50 p-4 rounded-lg">
        <input className="border p-2 rounded" placeholder="First Name" value={fName} onChange={e => setFName(e.target.value)} required />
        <input className="border p-2 rounded" placeholder="Last Name" value={lName} onChange={e => setLName(e.target.value)} required />
        <input className="border p-2 rounded" placeholder="Specialization" value={spec} onChange={e => setSpec(e.target.value)} required />
        <input className="border p-2 rounded" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} required />
        <button type="submit" className="bg-blue-600 text-white rounded">Add Doctor</button>
      </form>
      <table className="min-w-full bg-white border rounded-lg">
        <thead className="bg-blue-600 text-white">
          <tr><th className="p-3 text-left">Name</th><th className="p-3 text-left">Specialization</th><th className="p-3 text-center">Action</th></tr>
        </thead>
        <tbody>
          {doctors.map((d: any) => (
            <tr key={d.doctor_id} className="border-b">
              <td className="p-3">Dr. {d.first_name} {d.last_name}</td>
              <td className="p-3">{d.specialization}</td>
              <td className="p-3 text-center">
                <button onClick={() => handleDelete(d.doctor_id)} className="text-red-500">Remove</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default DoctorList;
